diff --git a/src/flb_mp.c b/src/flb_mp.c
index ec1825119..6e46a3142 100644
--- a/src/flb_mp.c
+++ b/src/flb_mp.c
@@ -508,19 +508,18 @@ struct flb_mp_accessor *flb_mp_accessor_create(struct mk_list *slist_patterns)
  *
  * @return The number of matches found.
  */
-static inline int accessor_key_find_matches(struct flb_mp_accessor *mpa,
+static inline int accessor_key_find_matches(struct flb_mp_accessor_match *matches,
+                                            int matches_size,
                                             msgpack_object *key,
                                             int* matched_indexes)
 {
     int i;
-    int count;
     int match_count = 0;
     int out_index = 0;
     struct flb_mp_accessor_match *match;

-    count = mk_list_size(&mpa->ra_list);
-    for (i = 0; i < count; i++) {
-        match = &mpa->matches[i];
+    for (i = 0; i < matches_size; i++) {
+        match = &matches[i];
         if (match->matched == FLB_FALSE) {
             continue;
         }
@@ -534,7 +533,8 @@ static inline int accessor_key_find_matches(struct flb_mp_accessor *mpa,
     return match_count;
 }

-static inline int accessor_sub_pack(struct flb_mp_accessor *mpa,
+static inline int accessor_sub_pack(struct flb_mp_accessor_match *matches,
+                                    int matches_size,
                                     int* matched_indexes,
                                     int match_count,
                                     msgpack_packer *mp_pck,
@@ -549,7 +549,7 @@ static inline int accessor_sub_pack(struct flb_mp_accessor *mpa,
     struct flb_mp_accessor_match *match;

     for (i = 0; i < match_count; i++) {
-        match = &mpa->matches[matched_indexes[i]];
+        match = &matches[matched_indexes[i]];
         if (match->key == key || match->key == val) {
             return FLB_FALSE;
         }
@@ -565,7 +565,7 @@ static inline int accessor_sub_pack(struct flb_mp_accessor *mpa,
             k = &val->via.map.ptr[i].key;
             v = &val->via.map.ptr[i].val;

-            ret = accessor_sub_pack(mpa, matched_indexes, match_count, mp_pck, k, v);
+            ret = accessor_sub_pack(matches, matches_size, matched_indexes, match_count, mp_pck, k, v);
             if (ret == FLB_TRUE) {
                 flb_mp_map_header_append(&mh);
             }
@@ -576,7 +576,7 @@ static inline int accessor_sub_pack(struct flb_mp_accessor *mpa,
         flb_mp_array_header_init(&mh, mp_pck);
         for (i = 0; i < val->via.array.size; i++) {
             v = &val->via.array.ptr[i];
-            ret = accessor_sub_pack(mpa, matched_indexes, match_count, mp_pck, NULL, v);
+            ret = accessor_sub_pack(matches, matches_size, matched_indexes, match_count, mp_pck, NULL, v);
             if (ret == FLB_TRUE) {
                 flb_mp_array_header_append(&mh);
             }
@@ -615,13 +615,20 @@ int flb_mp_accessor_keys_remove(struct flb_mp_accessor *mpa,
     struct flb_mp_map_header mh;
     msgpack_sbuffer mp_sbuf;
     msgpack_packer mp_pck;
+    struct flb_mp_accessor_match *local_matches = NULL;

     if (map->via.map.size == 0) {
         return FLB_FALSE;
     }

+    /* Create a local copy of matches to avoid race conditions */
+    local_matches = flb_calloc(mpa->matches_size, sizeof(struct flb_mp_accessor_match));
+    if (!local_matches) {
+        return -1;
+    }
+
     /* Reset matches cache */
-    memset(mpa->matches, '\0', mpa->matches_size);
+    memset(local_matches, '\0', mpa->matches_size * sizeof(struct flb_mp_accessor_match));

     mk_list_foreach(head, &mpa->ra_list) {
         mp_ra = mk_list_entry(head, struct flb_mp_accessor_ra, _head);
@@ -634,8 +641,8 @@ int flb_mp_accessor_keys_remove(struct flb_mp_accessor *mpa,
         /* Apply the record accessor rule against the map */
         ret = flb_ra_get_kv_pair(mp_ra->ra, *map, &s_key, &o_key, &o_val);
         if (ret == 0) {
-            /* There is a match, register in the matches table */
-            match = &mpa->matches[rule_id];
+            /* There is a match, register in the local matches table to avoid races */
+            match = &local_matches[rule_id];
             match->matched = FLB_TRUE;
             match->start_key = s_key;        /* Initial key path that matched */
             match->key = o_key;              /* Final key that matched */
@@ -676,7 +683,7 @@ int flb_mp_accessor_keys_remove(struct flb_mp_accessor *mpa,
          * Find all matching rules that match this 'key'. Return the number of matches or 0
          * if no matches were found. Found matches are stored in the 'matched_indexes' array.
          */
-        ret = accessor_key_find_matches(mpa, key, matched_indexes);
+        ret = accessor_key_find_matches(local_matches, mpa->matches_size, key, matched_indexes);
         if (ret == 0) {
             /* No matches, it's ok to pack the kv pair */
             flb_mp_map_header_append(&mh);
@@ -686,7 +693,7 @@ int flb_mp_accessor_keys_remove(struct flb_mp_accessor *mpa,
         else {
             /* The key has a match. Now we do a step-by-step packaging */

-            ret = accessor_sub_pack(mpa, matched_indexes, ret, &mp_pck, key, val);
+            ret = accessor_sub_pack(local_matches, mpa->matches_size, matched_indexes, ret, &mp_pck, key, val);
             if (ret == FLB_TRUE) {
                 flb_mp_map_header_append(&mh);
             }
@@ -699,6 +706,9 @@ int flb_mp_accessor_keys_remove(struct flb_mp_accessor *mpa,
     *out_buf = mp_sbuf.data;
     *out_size = mp_sbuf.size;

+    /* Clean up local matches */
+    flb_free(local_matches);
+
     return FLB_TRUE;
 }

