    89→static inline void safe_sds_cat(flb_sds_t *buf, const char *str, int len)
    90→{
    91→    flb_sds_t tmp;
    92→
    93→    tmp = flb_sds_cat(*buf, str, len);
    94→    if (tmp) {
    95→        *buf = tmp;
    96→    }
    97→}
    98→
    99→static inline void normalize_cat(struct flb_ra_parser *rp, flb_sds_t *name)
   100→{
   101→    int sub;
   102→    int len;
   103→    char tmp[64];
   104→    struct mk_list *s_head;
   105→    struct flb_ra_key *key;
   106→    struct flb_ra_subentry *entry;
   107→
   108→    /* Iterate record accessor keys */
   109→    key = rp->key;
   110→    if (rp->type == FLB_RA_PARSER_STRING) {
   111→        safe_sds_cat(name, key->name, flb_sds_len(key->name));
   112→    }
   113→    else if (rp->type == FLB_RA_PARSER_KEYMAP) {
   114→        safe_sds_cat(name, key->name, flb_sds_len(key->name));
   115→        if (mk_list_size(key->subkeys) > 0) {
   116→            safe_sds_cat(name, "_", 1);
   117→        }
   118→
   119→        sub = 0;
   120→        mk_list_foreach(s_head, key->subkeys) {
   121→            entry = mk_list_entry(s_head, struct flb_ra_subentry, _head);
   122→
   123→            if (sub > 0) {
   124→                safe_sds_cat(name, "_", 1);
   125→            }
   126→            if (entry->type == FLB_RA_PARSER_STRING) {
   127→                safe_sds_cat(name, entry->str, flb_sds_len(entry->str));
   128→            }
   129→            else if (entry->type == FLB_RA_PARSER_ARRAY_ID) {
   130→                len = snprintf(tmp, sizeof(tmp) -1, "%d",
   131→                               entry->array_id);
   132→                safe_sds_cat(name, tmp, len);
   133→            }
   134→            sub++;
   135→        }
   136→    }
   137→}
   138→
   139→static flb_sds_t normalize_ra_key_name(struct flb_loki *ctx,
   140→                                       struct flb_record_accessor *ra)
   141→{
   142→    int c = 0;
   143→    flb_sds_t name;
   144→    struct mk_list *head;
   145→    struct flb_ra_parser *rp;
   146→
   147→    name = flb_sds_create_size(128);
   148→    if (!name) {
   149→        return NULL;
   150→    }
   151→
   152→    mk_list_foreach(head, &ra->list) {
   153→        rp = mk_list_entry(head, struct flb_ra_parser, _head);
   154→        if (c > 0) {
   155→            flb_sds_cat_safe(&name, "_", 1);
   156→        }
   157→        normalize_cat(rp, &name);
   158→        c++;
   159→    }
   160→
   161→    return name;
   162→}
   163→
   164→void flb_loki_kv_destroy(struct flb_loki_kv *kv)
   165→{
   166→    /* destroy key and value */
   167→    flb_sds_destroy(kv->key);
   168→    if (kv->val_type == FLB_LOKI_KV_STR) {
   169→        flb_sds_destroy(kv->str_val);
   170→    }
   171→    else if (kv->val_type == FLB_LOKI_KV_RA) {
   172→        flb_ra_destroy(kv->ra_val);
   173→    }
   174→
   175→    if (kv->ra_key) {
   176→        flb_ra_destroy(kv->ra_key);
   177→    }
   178→
   179→    if (kv->key_normalized) {
   180→        flb_sds_destroy(kv->key_normalized);
   181→    }
   182→
   183→    flb_free(kv);
   184→}
   185→
   186→int flb_loki_kv_append(struct flb_loki *ctx, struct mk_list *list, char *key, char *val)
   187→{
   188→    int ra_count = 0;
   189→    int k_len;
   190→    int ret;
   191→    struct flb_loki_kv *kv;
   192→
   193→    if (!key) {
   194→        return -1;
   195→    }
   196→
   197→    if (!val && key[0] != '$') {
   198→        return -1;
   199→    }
   200→
   201→    kv = flb_calloc(1, sizeof(struct flb_loki_kv));
   202→    if (!kv) {
   203→        flb_errno();
   204→        return -1;
   205→    }
   206→
   207→    k_len = strlen(key);
   208→    if (key[0] == '$' && k_len >= 2 && isdigit(key[1])) {
   209→        flb_plg_error(ctx->ins,
   210→                      "key name for record accessor cannot start with a number: %s",
   211→                      key);
   212→        flb_free(kv);
   213→        return -1;
   214→    }
   215→
   216→    kv->key = flb_sds_create(key);
   217→    if (!kv->key) {
   218→        flb_free(kv);
   219→        return -1;
   220→    }
   221→
   222    /*
   223→     * If the key starts with a '$', it means its a record accessor pattern and
   224→     * the key value pair will be formed using the key name and it proper value.
   225→     */
   226→    if (key[0] == '$' && val == NULL) {
   227→        kv->ra_key = flb_ra_create(key, FLB_TRUE);
   228→        if (!kv->ra_key) {
   229→            flb_plg_error(ctx->ins,
   230→                          "invalid key record accessor pattern for key '%s'",
   231→                          key);
   232→            flb_loki_kv_destroy(kv);
   233→            return -1;
   234→        }
   235→
   236→        /* Normalize 'key name' using record accessor pattern */
   237→        kv->key_normalized = normalize_ra_key_name(ctx, kv->ra_key);
   238→        if (!kv->key_normalized) {
   239→            flb_plg_error(ctx->ins,
   240→                          "could not normalize key pattern name '%s'\n",
   241→                          kv->ra_key->pattern);
   242→            flb_loki_kv_destroy(kv);
   243→            return -1;
   244→        }
   245→        /* remove record keys placed as stream labels via 'labels' and 'label_keys' */
   246→        ret = flb_slist_add(&ctx->remove_keys_derived, key);
   247→        if (ret < 0) {
   248→            flb_loki_kv_destroy(kv);
   249→            return -1;
   250→        }
   251→        ra_count++;
   252→    }
   253→    else if (val[0] == '$') {
   254→        /* create a record accessor context */
   255→        kv->val_type = FLB_LOKI_KV_RA;
   256→        kv->ra_val = flb_ra_create(val, FLB_TRUE);
   257→        if (!kv->ra_val) {
   258→            flb_plg_error(ctx->ins,
   259→                          "invalid record accessor pattern for key '%s': %s",
   260→                          key, val);
   261→            flb_loki_kv_destroy(kv);
   262→            return -1;
   263→        }
   264→        ret = flb_slist_add(&ctx->remove_keys_derived, val);
   265→        if (ret < 0) {
   266→            flb_loki_kv_destroy(kv);
   267→            return -1;
   268→        }
   269→        ra_count++;
   270→    }
   271→    else {
   272→        kv->val_type = FLB_LOKI_KV_STR;
   273→        kv->str_val = flb_sds_create(val);
   274→        if (!kv->str_val) {
   275→            flb_loki_kv_destroy(kv);
   276→            return -1;
   277→        }
   278→    }
   279→    mk_list_add(&kv->_head, list);
   280→
   281→    /* return the number of record accessor values */
   282→    return ra_count;
   283→}
   284→
   285→static void flb_loki_kv_exit(struct flb_loki *ctx)
   286→{
   287→    struct mk_list *tmp;
   288→    struct mk_list *head;
   289→    struct flb_loki_kv *kv;
   290→
   291→    mk_list_foreach_safe(head, tmp, &ctx->labels_list) {
   292→        kv = mk_list_entry(head, struct flb_loki_kv, _head);
   293→
   294→        /* unlink and destroy */
   295→        mk_list_del(&kv->_head);
   296→        flb_loki_kv_destroy(kv);
   297→    }
   298→    mk_list_foreach_safe(head, tmp, &ctx->structured_metadata_list) {
   299→        kv = mk_list_entry(head, struct flb_loki_kv, _head);
   300→
   301→        /* unlink and destroy */
   302→        mk_list_del(&kv->_head);
   303→        flb_loki_kv_destroy(kv);
   304→    }
   305→    mk_list_foreach_safe(head, tmp, &ctx->structured_metadata_map_keys_list) {
   306→        kv = mk_list_entry(head, struct flb_loki_kv, _head);
   307→
   308→        /* unlink and destroy */
   309→        mk_list_del(&kv->_head);
   310→        flb_loki_kv_destroy(kv);
   311→    }
   312→}
   313→
   314→/* Pack a label key, it also perform sanitization of the characters */
   315→static int pack_label_key(msgpack_packer *mp_pck, char *key, int key_len)
   316→{
   317→    int i;
   318→    int k_len = key_len;
   319→    int is_digit = FLB_FALSE;
   320→    char *p;
   321→    size_t prev_size;
   322→
   323→    /* Normalize key name using the packed value */
   324→    if (isdigit(*key)) {
   325→        is_digit = FLB_TRUE;
   326→        k_len++;
   327→    }
   328→
   329→    /* key: pack the length */
   330→    msgpack_pack_str(mp_pck, k_len);
   331→    if (is_digit) {
   332→        msgpack_pack_str_body(mp_pck, "_", 1);
   333→    }
   334→
   335→    /* save the current offset */
   336→    prev_size = ((msgpack_sbuffer *) mp_pck->data)->size;
   337→
   338→    /* Pack the key name */
   339→    msgpack_pack_str_body(mp_pck, key, key_len);
   340→
   341→    /* 'p' will point to where the key was written */
   342→    p = (char *) (((msgpack_sbuffer*) mp_pck->data)->data + prev_size);
   343→
   344→    /* and sanitize the key characters */
   345→    for (i = 0; i < key_len; i++) {
   346→        if (!isalnum(p[i]) && p[i] != '_') {
   347→            p[i] = '_';
   348→        }
   349→    }
   350→
   351→    return 0;
   352→}
   353→
   354→static void pack_kv(struct flb_loki *ctx,
   355→                    msgpack_packer *mp_pck,
   356→                    char *tag, int tag_len,
   357→                    msgpack_object *map,
   358→                    struct flb_mp_map_header *mh,
   359→                    struct mk_list *list)
   360→{
   361→    struct mk_list *head;
   362→    struct flb_loki_kv *kv;
   363→    flb_sds_t ra_val;
   364→    mk_list_foreach(head, list) {
   365→        kv = mk_list_entry(head, struct flb_loki_kv, _head);
   366→
   367→        /* record accessor key/value pair */
   368→        if (kv->ra_key != NULL && kv->ra_val == NULL) {
   369→            ra_val = flb_ra_translate(kv->ra_key, tag, tag_len, *(map), NULL);
   370→            if (!ra_val || flb_sds_len(ra_val) == 0) {
   371→                /* if no value is retruned or if it's empty, just skip it */
   372→                flb_plg_debug(ctx->ins,
   373→                             "empty record accessor key translation for pattern: %s",
   374→                             kv->ra_key->pattern);
   375→            }
   376→            else {
   377→                /* Pack the key and value */
   378→                flb_mp_map_header_append(mh);
   379→
   380→                /* We skip the first '$' character since it won't be valid in Loki */
   381→                pack_label_key(mp_pck, kv->key_normalized,
   382→                               flb_sds_len(kv->key_normalized));
   383→
   384→                msgpack_pack_str(mp_pck, flb_sds_len(ra_val));
   385→                msgpack_pack_str_body(mp_pck, ra_val, flb_sds_len(ra_val));
   386→            }
   387→
   388→            if (ra_val) {
   389→                flb_sds_destroy(ra_val);
   390→            }
   391→            continue;
   392→        }
   393→
   394→        /*
   395→         * The code is a bit duplicated to be able to manage the exception of an
   396→         * invalid or empty value, on that case the k/v is skipped.
   397→         */
   398→        if (kv->val_type == FLB_LOKI_KV_STR) {
   399→            flb_mp_map_header_append(mh);
   400→            msgpack_pack_str(mp_pck, flb_sds_len(kv->key));
   401→            msgpack_pack_str_body(mp_pck, kv->key, flb_sds_len(kv->key));
   402→            msgpack_pack_str(mp_pck, flb_sds_len(kv->str_val));
   403→            msgpack_pack_str_body(mp_pck, kv->str_val, flb_sds_len(kv->str_val));
   404→        }
   405→        else if (kv->val_type == FLB_LOKI_KV_RA) {
   406→            /* record accessor type */
   407→            ra_val = flb_ra_translate(kv->ra_val, tag, tag_len, *(map), NULL);
   408→            if (!ra_val || flb_sds_len(ra_val) == 0) {
   409→                flb_plg_debug(ctx->ins, "could not translate record accessor");
   410→            }
   411→            else {
   412→                flb_mp_map_header_append(mh);
   413→                msgpack_pack_str(mp_pck, flb_sds_len(kv->key));
   414→                msgpack_pack_str_body(mp_pck, kv->key, flb_sds_len(kv->key));
   415→                msgpack_pack_str(mp_pck, flb_sds_len(ra_val));
   416→                msgpack_pack_str_body(mp_pck, ra_val, flb_sds_len(ra_val));
   417→            }
   418→
   419→            if (ra_val) {
   420→                flb_sds_destroy(ra_val);
   421→            }
   422→        }
   423→    }
   424→}
   425→
   426→/*
   427→ * Similar to pack_kv above, except will only use msgpack_objects of type
   428→ * MSGPACK_OBJECT_MAP, and will iterate over the keys adding each entry as a
   429→ * separate item. Non-string map values are serialised to JSON, as Loki requires
   430→ * all values to be strings.
   431→*/
   432→static void pack_maps(struct flb_loki *ctx,
   433→                        msgpack_packer *mp_pck,
   434→                        char *tag, int tag_len,
   435→                        msgpack_object *map,
   436→                        struct flb_mp_map_header *mh,
   437→                        struct mk_list *list)
   438→{
   439→    struct mk_list *head;
   440→    struct flb_loki_kv *kv;
   441→
   442→    msgpack_object *start_key;
   443→    msgpack_object *out_key;
   444→    msgpack_object *out_val;
   445→
   446→    msgpack_object_map accessed_map;
   447→    uint32_t accessed_map_index;
   448→    msgpack_object_kv accessed_map_kv;
   449→
   450→    char *accessed_map_val_json;
   451→
   452→    mk_list_foreach(head, list) {
   453→        /* get the flb_loki_kv for this iteration of the loop */
   454→        kv = mk_list_entry(head, struct flb_loki_kv, _head);
   455→
   456→        /* record accessor key/value pair */
   457→        if (kv->ra_key != NULL && kv->ra_val == NULL) {
   458→
   459→            /* try to get the value for the record accessor */
   460→            if (flb_ra_get_kv_pair(kv->ra_key, *map, &start_key, &out_key, &out_val)
   461→                == 0) {
   462→
   463→                /*
   464→                 * we require the value to be a map, or it doesn't make sense as
   465→                 * this is adding a map's key / values
   466→                 */
   467→                if (out_val->type != MSGPACK_OBJECT_MAP || out_val->via.map.size <= 0) {
   468→                    flb_plg_debug(ctx->ins, "No valid map data found for key %s",
   469→                                  kv->ra_key->pattern);
   470→                }
   471→                else {
   472→                    accessed_map = out_val->via.map;
   473→
   474→                    /* for each entry in the accessed map... */
   475→                    for (accessed_map_index = 0; accessed_map_index < accessed_map.size;
   476→                         accessed_map_index++) {
   477→
   478→                        /* get the entry */
   479→                        accessed_map_kv = accessed_map.ptr[accessed_map_index];
   480→
   481→                        /* Pack the key and value */
   482→                        flb_mp_map_header_append(mh);
   483→
   484→                        pack_label_key(mp_pck, (char*) accessed_map_kv.key.via.str.ptr,
   485→                                       accessed_map_kv.key.via.str.size);
   486→
   487→                        /* If the value is a string, just pack it... */
   488→                        if (accessed_map_kv.val.type == MSGPACK_OBJECT_STR) {
   489→                            msgpack_pack_str_with_body(mp_pck,
   490→                                                       accessed_map_kv.val.via.str.ptr,
   491→                                                       accessed_map_kv.val.via.str.size);
   492→                        }
   493→                        /*
   494→                         * ...otherwise convert value to JSON string, as Loki always
   495→                         * requires a string value
   496→                         */
   497→                        else {
   498→                            accessed_map_val_json = flb_msgpack_to_json_str(1024,
   499→                                &accessed_map_kv.val);
   500→                            if (accessed_map_val_json) {
   501→                                msgpack_pack_str_with_body(mp_pck, accessed_map_val_json,
   502→                                                         strlen(accessed_map_val_json));
   503→                                flb_free(accessed_map_val_json);
   504→                            }
   505→                        }
   506→                    }
   507→                }
   508→            }
   509→        }
   510→    }
   511→}
   512→
   513→static flb_sds_t pack_structured_metadata(struct flb_loki *ctx,
   514→                                          msgpack_packer *mp_pck,
   515→                                          char *tag, int tag_len,
   516→                                          msgpack_object *map)
   517→{
   518→    struct flb_mp_map_header mh;
   519→    /* Initialize dynamic map header */
   520→    flb_mp_map_header_init(&mh, mp_pck);
   521→    if (ctx->structured_metadata_map_keys) {
   522→        pack_maps(ctx, mp_pck, tag, tag_len, map, &mh,
   523→                  &ctx->structured_metadata_map_keys_list);
   524→    }
   525→    /*
   526→     * explicit structured_metadata entries override
   527→     * structured_metadata_map_keys entries
   528→     * */
   529→    if (ctx->structured_metadata) {
   530→        pack_kv(ctx, mp_pck, tag, tag_len, map, &mh, &ctx->structured_metadata_list);
   531→    }
   532→    flb_mp_map_header_end(&mh);
   533→    return 0;
   534→}
   535→
   536→static flb_sds_t pack_labels(struct flb_loki *ctx,
   537→                             msgpack_packer *mp_pck,
   538→                             char *tag, int tag_len,
   539→                             msgpack_object *map)
   540→{
   541→    int i;
   542→    struct flb_ra_value *rval = NULL;
   543→    msgpack_object k;
   544→    msgpack_object v;
   545→    struct flb_mp_map_header mh;
   546→
   547→    /* Initialize dynamic map header */
   548→    flb_mp_map_header_init(&mh, mp_pck);
   549→    pack_kv(ctx, mp_pck, tag, tag_len, map, &mh, &ctx->labels_list);
   550→
   551→    if (ctx->auto_kubernetes_labels == FLB_TRUE) {
   552→        rval = flb_ra_get_value_object(ctx->ra_k8s, *map);
   553→        if (rval && rval->o.type == MSGPACK_OBJECT_MAP) {
   554→            for (i = 0; i < rval->o.via.map.size; i++) {
   555→                k = rval->o.via.map.ptr[i].key;
   556→                v = rval->o.via.map.ptr[i].val;
   557→
   558→                if (k.type != MSGPACK_OBJECT_STR || v.type != MSGPACK_OBJECT_STR) {
   559→                    continue;
   560→                }
   561→
   562→                /* append the key/value pair */
   563→                flb_mp_map_header_append(&mh);
   564→
   565→                /* Pack key */
   566→                pack_label_key(mp_pck, (char *) k.via.str.ptr, k.via.str.size);
   567→
   568→                /* Pack the value */
   569→                msgpack_pack_str(mp_pck, v.via.str.size);
   570→                msgpack_pack_str_body(mp_pck, v.via.str.ptr,  v.via.str.size);
   571→            }
   572→        }
   573→
   574→        if (rval) {
   575→            flb_ra_key_value_destroy(rval);
   576→        }
   577→    }
   578→
   579→    /* Check if we added any label, if no one has been set, set the defaul 'job' */
   580→    if (mh.entries == 0) {
   581→        /* pack the default entry */
   582→        flb_mp_map_header_append(&mh);
   583→        msgpack_pack_str(mp_pck, 3);
   584→        msgpack_pack_str_body(mp_pck, "job", 3);
   585→        msgpack_pack_str(mp_pck, 10);
   586→        msgpack_pack_str_body(mp_pck, "fluent-bit", 10);
   587→    }
   588→    flb_mp_map_header_end(&mh);
   589→    return 0;
   590→}
   591→
   592→static int create_label_map_entry(struct flb_loki *ctx,
   593→                                  struct flb_sds_list *list, msgpack_object *val, int *ra_used)
   594→{
   595→    msgpack_object key;
   596→    flb_sds_t label_key;
   597→    flb_sds_t val_str;
   598→    int i;
   599→    int len;
   600→    int ret;
   601→
   602→    if (ctx == NULL || list == NULL || val == NULL || ra_used == NULL) {
   603→        return -1;
   604→    }
   605→
   606→    switch (val->type) {
   607→    case MSGPACK_OBJECT_STR:
   608→        label_key = flb_sds_create_len(val->via.str.ptr, val->via.str.size);
   609→        if (label_key == NULL) {
   610→            flb_errno();
   611→            return -1;
   612→        }
   613→
   614→        val_str = flb_ra_create_str_from_list(list);
   615→        if (val_str == NULL) {
   616→            flb_plg_error(ctx->ins, "[%s] flb_ra_create_from_list failed", __FUNCTION__);
   617→            flb_sds_destroy(label_key);
   618→            return -1;
   619→        }
   620→
   621→        /* for debugging
   622→          printf("label_key=%s val_str=%s\n", label_key, val_str);
   623→         */
   624→
   625→        ret = flb_loki_kv_append(ctx, &ctx->labels_list, label_key, val_str);
   626→        flb_sds_destroy(label_key);
   627→        flb_sds_destroy(val_str);
   628→        if (ret == -1) {
   629→            return -1;
   630→        }
   631→        *ra_used = *ra_used + 1;
   632→
   633→        break;
   634→    case MSGPACK_OBJECT_MAP:
   635→        len = val->via.map.size;
   636→        for (i=0; i<len; i++) {
   637→            key = val->via.map.ptr[i].key;
   638→            if (key.type != MSGPACK_OBJECT_STR) {
   639→                flb_plg_error(ctx->ins, "[%s] key is not string", __FUNCTION__);
   640→                return -1;
   641→            }
   642→            ret = flb_sds_list_add(list, (char*)key.via.str.ptr, key.via.str.size);
   643→            if (ret < 0) {
   644→                flb_plg_error(ctx->ins, "[%s] flb_sds_list_add failed", __FUNCTION__);
   645→                return -1;
   646→            }
   647→
   648→            ret = create_label_map_entry(ctx, list, &val->via.map.ptr[i].val, ra_used);
   649→            if (ret < 0) {
   650→                return -1;
   651→            }
   652→
   653→            ret = flb_sds_list_del_last_entry(list);
   654→            if (ret < 0) {
   655→                flb_plg_error(ctx->ins, "[%s] flb_sds_list_del_last_entry failed", __FUNCTION__);
   656→                return -1;
   657→            }
   658→        }
   659→
   660→        break;
   661→    default:
   662→        flb_plg_error(ctx->ins, "[%s] value type is not str or map. type=%d", __FUNCTION__, val->type);
   663→        return -1;
   664→    }
   665→    return 0;
   666→}
   667→
   668→static int create_label_map_entries(struct flb_loki *ctx,
   669→                                    char *msgpack_buf, size_t msgpack_size, int *ra_used)
   670→{
   671→    struct flb_sds_list *list = NULL;
   672→    msgpack_unpacked result;
   673→    size_t off = 0;
   674→    int i;
   675→    int len;
   676→    int ret;
   677→    msgpack_object key;
   678→
   679→    if (ctx == NULL || msgpack_buf == NULL || ra_used == NULL) {
   680→        return -1;
   681→    }
   682→
   683→    msgpack_unpacked_init(&result);
   684→    while(msgpack_unpack_next(&result, msgpack_buf, msgpack_size, &off) == MSGPACK_UNPACK_SUCCESS) {
   685→        if (result.data.type != MSGPACK_OBJECT_MAP) {
   686→            flb_plg_error(ctx->ins, "[%s] data type is not map", __FUNCTION__);
   687→            msgpack_unpacked_destroy(&result);
   688→            return -1;
   689→        }
   690→
   691→        len = result.data.via.map.size;
   692→        for (i=0; i<len; i++) {
   693→            list = flb_sds_list_create();
   694→            if (list == NULL) {
   695→                flb_plg_error(ctx->ins, "[%s] flb_sds_list_create failed", __FUNCTION__);
   696→                msgpack_unpacked_destroy(&result);
   697→                return -1;
   698→            }
   699→            key = result.data.via.map.ptr[i].key;
   700→            if (key.type != MSGPACK_OBJECT_STR) {
   701→                flb_plg_error(ctx->ins, "[%s] key is not string", __FUNCTION__);
   702→                flb_sds_list_destroy(list);
   703→                msgpack_unpacked_destroy(&result);
   704→                return -1;
   705→            }
   706→
   707→            ret = flb_sds_list_add(list, (char*)key.via.str.ptr, key.via.str.size);
   708→            if (ret < 0) {
   709→                flb_plg_error(ctx->ins, "[%s] flb_sds_list_add failed", __FUNCTION__);
   710→                flb_sds_list_destroy(list);
   711→                msgpack_unpacked_destroy(&result);
   712→                return -1;
   713→            }
   714→
   715→            ret = create_label_map_entry(ctx, list, &result.data.via.map.ptr[i].val, ra_used);
   716→            if (ret < 0) {
   717→                flb_plg_error(ctx->ins, "[%s] create_label_map_entry failed", __FUNCTION__);
   718→                flb_sds_list_destroy(list);
   719→                msgpack_unpacked_destroy(&result);
   720→                return -1;
   721→            }
   722→
   723→            flb_sds_list_destroy(list);
   724→            list = NULL;
   725→        }
   726→    }
   727→
   728→    msgpack_unpacked_destroy(&result);
   729→
   730→    return 0;
   731→}
   732→
   733→static int read_label_map_path_file(struct flb_output_instance *ins, flb_sds_t path,
   734→                                    char **out_buf, size_t *out_size)
   735→{
   736→    int ret;
   737→    int root_type;
   738→    char *buf = NULL;
   739→    char *msgp_buf = NULL;
   740→    FILE *fp = NULL;
   741→    struct stat st;
   742→    size_t file_size;
   743→    size_t ret_size;
   744→
   745→    ret = access(path, R_OK);
   746→    if (ret < 0) {
   747→        flb_errno();
   748→        flb_plg_error(ins, "can't access %s", path);
   749→        return -1;
   750→    }
   751→
   752→    ret = stat(path, &st);
   753→    if (ret < 0) {
   754→        flb_errno();
   755→        flb_plg_error(ins, "stat failed %s", path);
   756→        return -1;
   757→    }
   758→    file_size = st.st_size;
   759→
   760→    fp = fopen(path, "r");
   761→    if (fp == NULL) {
   762→        flb_plg_error(ins, "can't open %s", path);
   763→        return -1;
   764→    }
   765→
   766→    buf = flb_malloc(file_size);
   767→    if (buf == NULL) {
   768→        flb_plg_error(ins, "malloc failed");
   769→        fclose(fp);
   770→        return -1;
   771→    }
   772→
   773→    ret_size = fread(buf, 1, file_size, fp);
   774→    if (ret_size < file_size && feof(fp) != 0) {
   775→        flb_plg_error(ins, "fread failed");
   776→        fclose(fp);
   777→        flb_free(buf);
   778→        return -1;
   779→    }
   780→
   781→    ret = flb_pack_json(buf, file_size, &msgp_buf, &ret_size, &root_type, NULL);
   782→    if (ret < 0) {
   783→        flb_plg_error(ins, "flb_pack_json failed");
   784→        fclose(fp);
   785→        flb_free(buf);
   786→        return -1;
   787→    }
   788→
   789→    *out_buf = msgp_buf;
   790→    *out_size = ret_size;
   791→
   792→    fclose(fp);
   793→    flb_free(buf);
   794→    return 0;
   795→}
   796→
   797→static int load_label_map_path(struct flb_loki *ctx, flb_sds_t path, int *ra_used)
   798→{
   799→    int ret;
   800→    char *msgpack_buf = NULL;
   801→    size_t msgpack_size;
   802→
   803→    ret = read_label_map_path_file(ctx->ins, path, &msgpack_buf, &msgpack_size);
   804→    if (ret < 0) {
   805→        return -1;
   806→    }
   807→
   808→    ret = create_label_map_entries(ctx, msgpack_buf, msgpack_size, ra_used);
   809→    if (ret < 0) {
   810→        flb_free(msgpack_buf);
   811→        return -1;
   812→    }
   813→
   814→    if (msgpack_buf != NULL) {
   815→        flb_free(msgpack_buf);
   816→    }
   817→
   818→    return 0;
   819→}
   820→
   821→static int parse_kv(struct flb_loki *ctx, struct mk_list *kv, struct mk_list *list, int *ra_used)
   822→{
   823→    int ret;
   824→    char *p;
   825→    flb_sds_t key;
   826→    flb_sds_t val;
   827→    struct mk_list *head;
   828→    struct flb_slist_entry *entry;
   829→
   830→    if (ctx == NULL || list == NULL || ra_used == NULL) {
   831→        return -1;
   832→    }
   833→
   834→    mk_list_foreach(head, kv) {
   835→        entry = mk_list_entry(head, struct flb_slist_entry, _head);
   836→
   837→        /* record accessor label key ? */
   838→        if (entry->str[0] == '$') {
   839→            ret = flb_loki_kv_append(ctx, list, entry->str, NULL);
   840→            if (ret == -1) {
   841→                return -1;
   842→            }
   843→            else if (ret > 0) {
   844→                (*ra_used)++;
   845→            }
   846→            continue;
   847→        }
   848→
   849→        p = strchr(entry->str, '=');
   850→        if (!p) {
   851→            flb_plg_error(ctx->ins, "invalid key value pair on '%s'",
   852→                          entry->str);
   853→            return -1;
   854→        }
   855→
   856→        key = flb_sds_create_size((p - entry->str) + 1);
   857→        flb_sds_cat_safe(&key, entry->str, p - entry->str);
   858→        val = flb_sds_create(p + 1);
   859→        if (!key) {
   860→            flb_plg_error(ctx->ins,
   861→                          "invalid key value pair on '%s'",
   862→                          entry->str);
   863→            return -1;
   864→        }
   865→        if (!val || flb_sds_len(val) == 0) {
   866→            flb_plg_error(ctx->ins,
   867→                          "invalid key value pair on '%s'",
   868→                          entry->str);
   869→            flb_sds_destroy(key);
   870→            return -1;
   871→        }
   872→        ret = flb_loki_kv_append(ctx, list, key, val);
   873→        flb_sds_destroy(key);
   874→        flb_sds_destroy(val);
   875→
   876→        if (ret == -1) {
   877→            return -1;
   878→        }
   879→        else if (ret > 0) {
   880→            (*ra_used)++;
   881→        }
   882→    }
   883→    return 0;
   884→}
   885→
   886→static int parse_labels(struct flb_loki *ctx)
   887→{
   888→    int ret;
   889→    int ra_used = 0;
   890→    struct mk_list *head;
   891→    struct flb_slist_entry *entry;
   892→
   893→    flb_loki_kv_init(&ctx->labels_list);
   894→    flb_loki_kv_init(&ctx->structured_metadata_list);
   895→    flb_loki_kv_init(&ctx->structured_metadata_map_keys_list);
   896→
   897→    if (ctx->structured_metadata) {
   898→        ret = parse_kv(ctx, ctx->structured_metadata, &ctx->structured_metadata_list, &ra_used);
   899→        if (ret == -1) {
   900→            return -1;
   901→        }
   902→    }
   903→
   904→    /* Append structured metadata map keys set in the configuration */
   905→    if (ctx->structured_metadata_map_keys) {
   906→        mk_list_foreach(head, ctx->structured_metadata_map_keys) {
   907→            entry = mk_list_entry(head, struct flb_slist_entry, _head);
   908→            if (entry->str[0] != '$') {
   909→                flb_plg_error(ctx->ins,
   910→                              "invalid structured metadata map key, the name must start "
   911→                              "with '$'");
   912→                return -1;
   913→            }
   914→
   915→            ret = flb_loki_kv_append(ctx, &ctx->structured_metadata_map_keys_list,
   916→                                     entry->str, NULL);
   917→            if (ret == -1) {
   918→                return -1;
   919→            }
   920→            else if (ret > 0) {
   921→                ra_used++;
   922→            }
   923→        }
   924→    }
   925→
   926→    if (ctx->labels) {
   927→        ret = parse_kv(ctx, ctx->labels, &ctx->labels_list, &ra_used);
   928→        if (ret == -1) {
   929→            return -1;
   930→        }
   931→    }
   932→
   933→    /* Append label keys set in the configuration */
   934→    if (ctx->label_keys) {
   935→        mk_list_foreach(head, ctx->label_keys) {
   936→            entry = mk_list_entry(head, struct flb_slist_entry, _head);
   937→            if (entry->str[0] != '$') {
   938→                flb_plg_error(ctx->ins,
   939→                              "invalid label key, the name must start with '$'");
   940→                return -1;
   941→            }
   942→
   943→            ret = flb_loki_kv_append(ctx, &ctx->labels_list, entry->str, NULL);
   944→            if (ret == -1) {
   945→                return -1;
   946→            }
   947→            else if (ret > 0) {
   948→                ra_used++;
   949→            }
   950→        }
   951→    }
   952→
   953→    /* label_map_path */
   954→    if (ctx->label_map_path) {
   955→        ret = load_label_map_path(ctx, ctx->label_map_path, &ra_used);
   956→        if (ret != 0) {
   957→            flb_plg_error(ctx->ins, "failed to load label_map_path");
   958→        }
   959→    }
   960→
   961→    if (ctx->auto_kubernetes_labels == FLB_TRUE) {
   962→        ctx->ra_k8s = flb_ra_create("$kubernetes['labels']", FLB_TRUE);
   963→        if (!ctx->ra_k8s) {
   964→            flb_plg_error(ctx->ins,
   965→                          "could not create record accessor for Kubernetes labels");
   966→            return -1;
   967→        }
   968→    }
   969→
   970→    /*
   971→     * If the variable 'ra_used' is greater than zero, means that record accessor is
   972→     * being used to compose the stream labels.
   973→     */
   974→    ctx->ra_used = ra_used;
   975→    return 0;
   976→}
   977→
   978→static int key_is_duplicated(struct mk_list *list, char *str, int len)
   979→{
   980→    struct mk_list *head;
   981→    struct flb_slist_entry *entry;
   982→
   983→    mk_list_foreach(head, list) {
   984→        entry = mk_list_entry(head, struct flb_slist_entry, _head);
   985→        if (flb_sds_len(entry->str) == len &&
   986→            strncmp(entry->str, str, len) == 0) {
   987→            return FLB_TRUE;
   988→        }
   989→    }
   990→
   991→    return FLB_FALSE;
   992→}
   993→
   994→static int prepare_remove_keys(struct flb_loki *ctx)
   995→{
   996→    int ret;
   997→    int len;
   998→    int size;
   999→    char *tmp;
  1000→    struct mk_list *head;
  1001→    struct flb_slist_entry *entry;
  1002→    struct mk_list *patterns;
  1003→
  1004→    patterns = &ctx->remove_keys_derived;
  1005→
  1006→    /* Add remove keys set in the configuration */
  1007→    if (ctx->remove_keys) {
  1008→        mk_list_foreach(head, ctx->remove_keys) {
  1009→            entry = mk_list_entry(head, struct flb_slist_entry, _head);
  1010→
  1011→            if (entry->str[0] != '$') {
  1012→                tmp = flb_malloc(flb_sds_len(entry->str) + 2);
  1013→                if (!tmp) {
  1014→                    flb_errno();
  1015→                    continue;
  1016→                }
  1017→                else {
  1018→                    tmp[0] = '$';
  1019→                    len = flb_sds_len(entry->str);
  1020→                    memcpy(tmp + 1, entry->str, len);
  1021→                    tmp[len + 1] = '\0';
  1022→                    len++;
  1023→                }
  1024→            }
  1025→            else {
  1026→                tmp = entry->str;
  1027→                len = flb_sds_len(entry->str);
  1028→            }
  1029→
  1030→            ret = key_is_duplicated(patterns, tmp, len);
  1031→            if (ret == FLB_TRUE) {
  1032→                if (entry->str != tmp) {
  1033→                    flb_free(tmp);
  1034→                }
  1035→                continue;
  1036→            }
  1037→
  1038→            ret = flb_slist_add_n(patterns, tmp, len);
  1039→            if (entry->str != tmp) {
  1040→                flb_free(tmp);
  1041→            }
  1042→            if (ret < 0) {
  1043→                return -1;
  1044→            }
  1045→        }
  1046→        size = mk_list_size(patterns);
  1047→        flb_plg_debug(ctx->ins, "remove_mpa size: %d", size);
  1048→        if (size > 0) {
  1049→            ctx->remove_mpa = flb_mp_accessor_create(patterns);
  1050→            if (ctx->remove_mpa == NULL) {
  1051→                return -1;
  1052→            }
  1053→        }
  1054→    }
  1055→
  1056→    return 0;
  1057→}
  1058→
  1059→static void loki_config_destroy(struct flb_loki *ctx)
  1060→{
  1061→    if (ctx->u) {
  1062→        flb_upstream_destroy(ctx->u);
  1063→    }
  1064→
  1065→    if (ctx->ra_k8s) {
  1066→        flb_ra_destroy(ctx->ra_k8s);
  1067→    }
  1068→    if (ctx->ra_tenant_id_key) {
  1069→        flb_ra_destroy(ctx->ra_tenant_id_key);
  1070→    }
  1071→
  1072→    if (ctx->remove_mpa) {
  1073→        flb_mp_accessor_destroy(ctx->remove_mpa);
  1074→    }
  1075→    flb_slist_destroy(&ctx->remove_keys_derived);
  1076→
  1077→    flb_loki_kv_exit(ctx);
  1078→    flb_free(ctx);
  1079→}
  1080→
  1081→static struct flb_loki *loki_config_create(struct flb_output_instance *ins,
  1082→                                           struct flb_config *config)
  1083→{
  1084→    int ret;
  1085→    int tmp;
  1086→    int io_flags = 0;
  1087→    struct flb_loki *ctx;
  1088→    struct flb_upstream *upstream;
  1089→    char *compress;
  1090→    char *drop_single_key;
  1091→
  1092→    /* Create context */
  1093→    ctx = flb_calloc(1, sizeof(struct flb_loki));
  1094→    if (!ctx) {
  1095→        flb_errno();
  1096→        return NULL;
  1097→    }
  1098→    ctx->ins = ins;
  1099→    flb_loki_kv_init(&ctx->labels_list);
  1100→    flb_loki_kv_init(&ctx->structured_metadata_list);
  1101→    flb_loki_kv_init(&ctx->structured_metadata_map_keys_list);
  1102→
  1103→    /* Register context with plugin instance */
  1104→    flb_output_set_context(ins, ctx);
  1105→
  1106→    /* Set networking defaults */
  1107→    flb_output_net_default(FLB_LOKI_HOST, FLB_LOKI_PORT, ins);
  1108→
  1109→    /* Load config map */
  1110→    ret = flb_output_config_map_set(ins, (void *) ctx);
  1111→    if (ret == -1) {
  1112→        return NULL;
  1113→    }
  1114→
  1115→    /* Initialize final remove_keys list */
  1116→    flb_slist_create(&ctx->remove_keys_derived);
  1117→
  1118→    /* Parse labels */
  1119→    ret = parse_labels(ctx);
  1120→    if (ret == -1) {
  1121→        return NULL;
  1122→    }
  1123→
  1124→    /* Load remove keys */
  1125→    ret = prepare_remove_keys(ctx);
  1126→    if (ret == -1) {
  1127→        return NULL;
  1128→    }
  1129→
  1130→    /* tenant_id_key */
  1131→    if (ctx->tenant_id_key_config) {
  1132→        ctx->ra_tenant_id_key = flb_ra_create(ctx->tenant_id_key_config, FLB_FALSE);
  1133→        if (!ctx->ra_tenant_id_key) {
  1134→            flb_plg_error(ctx->ins,
  1135→                          "could not create record accessor for Tenant ID");
  1136→        }
  1137→    }
  1138→
  1139→    /* Compress (gzip) */
  1140→    compress = (char *) flb_output_get_property("compress", ins);
  1141→    ctx->compress_gzip = FLB_FALSE;
  1142→    if (compress) {
  1143→        if (strcasecmp(compress, "gzip") == 0) {
  1144→            ctx->compress_gzip = FLB_TRUE;
  1145→        }
  1146→    }
  1147→
  1148→    /* Drop Single Key */
  1149→    drop_single_key = (char *) flb_output_get_property("drop_single_key", ins);
  1150→    ctx->out_drop_single_key = FLB_LOKI_DROP_SINGLE_KEY_OFF;
  1151→    if (drop_single_key) {
  1152→        if (strcasecmp(drop_single_key, "raw") == 0) {
  1153→            ctx->out_drop_single_key = FLB_LOKI_DROP_SINGLE_KEY_ON | FLB_LOKI_DROP_SINGLE_KEY_RAW;
  1154→        }
  1155→        else {
  1156→            tmp = flb_utils_bool(drop_single_key);
  1157→            if (tmp == FLB_TRUE) {
  1158→                ctx->out_drop_single_key = FLB_LOKI_DROP_SINGLE_KEY_ON;
  1159→            }
  1160→            else if (tmp == FLB_FALSE) {
  1161→                ctx->out_drop_single_key = FLB_LOKI_DROP_SINGLE_KEY_OFF;
  1162→            }
  1163→            else {
  1164→                flb_plg_error(ctx->ins, "invalid 'drop_single_key' value: %s",
  1165→                              ctx->drop_single_key);
  1166→                return NULL;
  1167→            }
  1168→        }
  1169→    }
  1170→
  1171→    /* Line Format */
  1172→    if (strcasecmp(ctx->line_format, "json") == 0) {
  1173→        ctx->out_line_format = FLB_LOKI_FMT_JSON;
  1174→    }
  1175→    else if (strcasecmp(ctx->line_format, "key_value") == 0) {
  1176→        ctx->out_line_format = FLB_LOKI_FMT_KV;
  1177→    }
  1178→    else {
  1179→        flb_plg_error(ctx->ins, "invalid 'line_format' value: %s",
  1180→                      ctx->line_format);
  1181→        return NULL;
  1182→    }
  1183→
  1184→    /* use TLS ? */
  1185→    if (ins->use_tls == FLB_TRUE) {
  1186→        io_flags = FLB_IO_TLS;
  1187→    }
  1188→    else {
  1189→        io_flags = FLB_IO_TCP;
  1190→    }
  1191→
  1192→    if (ins->host.ipv6 == FLB_TRUE) {
  1193→        io_flags |= FLB_IO_IPV6;
  1194→    }
  1195→
  1196→    /* Create Upstream connection context */
  1197→    upstream = flb_upstream_create(config,
  1198→                                   ins->host.name,
  1199→                                   ins->host.port,
  1200→                                   io_flags,
  1201→                                   ins->tls);
  1202→    if (!upstream) {
  1203→        return NULL;
  1204→    }
  1205→    ctx->u = upstream;
  1206→    flb_output_upstream_set(ctx->u, ins);
  1207→    ctx->tcp_port = ins->host.port;
  1208→    ctx->tcp_host = ins->host.name;
  1209→
  1210→    return ctx;
  1211→}
