  1213→/*
  1214→ * Convert struct flb_tm timestamp value to nanoseconds and then it pack it as
  1215→ * a string.
  1216→ */
  1217→static void pack_timestamp(msgpack_packer *mp_pck, struct flb_time *tms)
  1218→{
  1219→    int len;
  1220→    char buf[64];
  1221→    uint64_t nanosecs;
  1222→
  1223→    /* convert to nanoseconds */
  1224→    nanosecs = flb_time_to_nanosec(tms);
  1225→
  1226→    /* format as a string */
  1227→    len = snprintf(buf, sizeof(buf) - 1, "%" PRIu64, nanosecs);
  1228→
  1229→    /* pack the value */
  1230→    msgpack_pack_str(mp_pck, len);
  1231→    msgpack_pack_str_body(mp_pck, buf, len);
  1232→}
  1233→
  1234→
  1235→static void pack_format_line_value(flb_sds_t *buf, msgpack_object *val)
  1236→{
  1237→    int i;
  1238→    int len;
  1239→    char temp[512];
  1240→    msgpack_object k;
  1241→    msgpack_object v;
  1242→
  1243→    if (val->type == MSGPACK_OBJECT_STR) {
  1244→        safe_sds_cat(buf, "\"", 1);
  1245→        safe_sds_cat(buf, val->via.str.ptr, val->via.str.size);
  1246→        safe_sds_cat(buf, "\"", 1);
  1247→    }
  1248→    else if (val->type == MSGPACK_OBJECT_NIL) {
  1249→        safe_sds_cat(buf, "null", 4);
  1250→    }
  1251→    else if (val->type == MSGPACK_OBJECT_BOOLEAN) {
  1252→        if (val->via.boolean) {
  1253→            safe_sds_cat(buf, "true", 4);
  1254→        }
  1255→        else {
  1256→            safe_sds_cat(buf, "false", 5);
  1257→        }
  1258→    }
  1259→    else if (val->type == MSGPACK_OBJECT_POSITIVE_INTEGER) {
  1260→        len = snprintf(temp, sizeof(temp)-1, "%"PRIu64, val->via.u64);
  1261→        safe_sds_cat(buf, temp, len);
  1262→    }
  1263→    else if (val->type == MSGPACK_OBJECT_NEGATIVE_INTEGER) {
  1264→        len = snprintf(temp, sizeof(temp)-1, "%"PRId64, val->via.i64);
  1265→        safe_sds_cat(buf, temp, len);
  1266→    }
  1267→    else if (val->type == MSGPACK_OBJECT_FLOAT32 ||
  1268→             val->type == MSGPACK_OBJECT_FLOAT64) {
  1269→        if (val->via.f64 == (double)(long long int) val->via.f64) {
  1270→            len = snprintf(temp, sizeof(temp)-1, "%.1f", val->via.f64);
  1271→        }
  1272→        else {
  1273→            len = snprintf(temp, sizeof(temp)-1, "%.16g", val->via.f64);
  1274→        }
  1275→        safe_sds_cat(buf, temp, len);
  1276→    }
  1277→    else if (val->type == MSGPACK_OBJECT_ARRAY) {
  1278→        safe_sds_cat(buf, "\"[", 2);
  1279→        for (i = 0; i < val->via.array.size; i++) {
  1280→            v = val->via.array.ptr[i];
  1281→            if (i > 0) {
  1282→                safe_sds_cat(buf, " ", 1);
  1283→            }
  1284→            pack_format_line_value(buf, &v);
  1285→        }
  1286→        safe_sds_cat(buf, "]\"", 2);
  1287→    }
  1288→    else if (val->type == MSGPACK_OBJECT_MAP) {
  1289→        safe_sds_cat(buf, "\"map[", 5);
  1290→
  1291→        for (i = 0; i < val->via.map.size; i++) {
  1292→            k = val->via.map.ptr[i].key;
  1293→            v = val->via.map.ptr[i].val;
  1294→
  1295→            if (k.type != MSGPACK_OBJECT_STR) {
  1296→                continue;
  1297→            }
  1298→
  1299→            if (i > 0) {
  1300→                safe_sds_cat(buf, " ", 1);
  1301→            }
  1302→
  1303→            safe_sds_cat(buf, k.via.str.ptr, k.via.str.size);
  1304→            safe_sds_cat(buf, ":", 1);
  1305→            pack_format_line_value(buf, &v);
  1306→        }
  1307→        safe_sds_cat(buf, "]\"", 2);
  1308→    }
  1309→    else {
  1310→
  1311→        return;
  1312→    }
  1313→}
  1314→
  1315→// seek tenant id from map and set it to dynamic_tenant_id
  1316→static int get_tenant_id_from_record(struct flb_loki *ctx, msgpack_object *map,
  1317→                                     flb_sds_t *dynamic_tenant_id)
  1318→{
  1319→    struct flb_ra_value *rval = NULL;
  1320→    flb_sds_t tmp_str;
  1321→    int cmp_len;
  1322→
  1323→    rval = flb_ra_get_value_object(ctx->ra_tenant_id_key, *map);
  1324→
  1325→    if (rval == NULL) {
  1326→        flb_plg_warn(ctx->ins, "the value of %s is missing",
  1327→                     ctx->tenant_id_key_config);
  1328→        return -1;
  1329→    }
  1330→    else if (rval->o.type != MSGPACK_OBJECT_STR) {
  1331→        flb_plg_warn(ctx->ins, "the value of %s is not string",
  1332→                     ctx->tenant_id_key_config);
  1333→        flb_ra_key_value_destroy(rval);
  1334→        return -1;
  1335→    }
  1336→
  1337→    tmp_str = flb_sds_create_len(rval->o.via.str.ptr,
  1338→                                 rval->o.via.str.size);
  1339→    if (tmp_str == NULL) {
  1340→        flb_plg_warn(ctx->ins, "cannot create tenant ID string from record");
  1341→        flb_ra_key_value_destroy(rval);
  1342→        return -1;
  1343→    }
  1344→
  1345→    // check if already dynamic_tenant_id is set.
  1346→    if (*dynamic_tenant_id != NULL) {
  1347→        cmp_len = flb_sds_len(*dynamic_tenant_id);
  1348→
  1349→        if ((rval->o.via.str.size == cmp_len) &&
  1350→            flb_sds_cmp(tmp_str, *dynamic_tenant_id, cmp_len) == 0) {
  1351→            // tenant_id is same. nothing to do.
  1352→            flb_ra_key_value_destroy(rval);
  1353→            flb_sds_destroy(tmp_str);
  1354→
  1355→            return 0;
  1356→        }
  1357→
  1358→        flb_plg_warn(ctx->ins, "Tenant ID is overwritten %s -> %s",
  1359→                     *dynamic_tenant_id, tmp_str);
  1360→
  1361→        flb_sds_destroy(*dynamic_tenant_id);
  1362→    }
  1363→
  1364→    // this sds will be released after setting http header.
  1365→    *dynamic_tenant_id = tmp_str;
  1366→    flb_plg_debug(ctx->ins, "Tenant ID is %s", *dynamic_tenant_id);
  1367→
  1368→    flb_ra_key_value_destroy(rval);
  1369→    return 0;
  1370→}
  1371→
  1372→static int pack_record(struct flb_loki *ctx,
  1373→                       msgpack_packer *mp_pck, msgpack_object *rec,
  1374→                       flb_sds_t *dynamic_tenant_id)
  1375→{
  1376→    int i;
  1377→    int skip = 0;
  1378→    int len;
  1379→    int ret;
  1380→    int size_hint = 1024;
  1381→    char *line;
  1382→    flb_sds_t buf;
  1383→    msgpack_object key;
  1384→    msgpack_object val;
  1385→    char *tmp_sbuf_data = NULL;
  1386→    size_t tmp_sbuf_size;
  1387→    msgpack_unpacked mp_buffer;
  1388→    size_t off = 0;
  1389→
  1390→    /*
  1391→     * Get tenant id from record before removing keys.
  1392→     * https://github.com/fluent/fluent-bit/issues/6207
  1393→     */
  1394→    if (ctx->ra_tenant_id_key && rec->type == MSGPACK_OBJECT_MAP) {
  1395→        get_tenant_id_from_record(ctx, rec, dynamic_tenant_id);
  1396→    }
  1397→
  1398→    /* Remove keys in remove_keys */
  1399→    msgpack_unpacked_init(&mp_buffer);
  1400→    if (ctx->remove_mpa) {
  1401→        ret = flb_mp_accessor_keys_remove(ctx->remove_mpa, rec,
  1402→                                          (void *) &tmp_sbuf_data, &tmp_sbuf_size);
  1403→        if (ret == FLB_TRUE) {
  1404→            ret = msgpack_unpack_next(&mp_buffer, tmp_sbuf_data, tmp_sbuf_size, &off);
  1405→            if (ret != MSGPACK_UNPACK_SUCCESS) {
  1406→                flb_free(tmp_sbuf_data);
  1407→                msgpack_unpacked_destroy(&mp_buffer);
  1408→                return -1;
  1409→            }
  1410→            rec = &mp_buffer.data;
  1411→        }
  1412→    }
  1413→
  1414→    /* Drop single key */
  1415→    if (ctx->out_drop_single_key & FLB_LOKI_DROP_SINGLE_KEY_ON &&
  1416→        rec->type == MSGPACK_OBJECT_MAP && rec->via.map.size == 1) {
  1417→        val = rec->via.map.ptr[0].val;
  1418→
  1419→        if (ctx->out_line_format == FLB_LOKI_FMT_JSON) {
  1420→            if (val.type == MSGPACK_OBJECT_STR &&
  1421→                ctx->out_drop_single_key & FLB_LOKI_DROP_SINGLE_KEY_RAW) {
  1422→                msgpack_pack_str(mp_pck, val.via.str.size);
  1423→                msgpack_pack_str_body(mp_pck, val.via.str.ptr, val.via.str.size);
  1424→
  1425→                msgpack_unpacked_destroy(&mp_buffer);
  1426→                if (tmp_sbuf_data) {
  1427→                    flb_free(tmp_sbuf_data);
  1428→                }
  1429→
  1430→                return 0;
  1431→            }
  1432→            else {
  1433→                rec = &val;
  1434→            }
  1435→        }
  1436→        else if (ctx->out_line_format == FLB_LOKI_FMT_KV) {
  1437→            if (val.type == MSGPACK_OBJECT_STR) {
  1438→                msgpack_pack_str(mp_pck, val.via.str.size);
  1439→                msgpack_pack_str_body(mp_pck, val.via.str.ptr, val.via.str.size);
  1440→            } else {
  1441→                buf = flb_sds_create_size(size_hint);
  1442→                if (!buf) {
  1443→                    msgpack_unpacked_destroy(&mp_buffer);
  1444→                    if (tmp_sbuf_data) {
  1445→                        flb_free(tmp_sbuf_data);
  1446→                    }
  1447→                    return -1;
  1448→                }
  1449→                pack_format_line_value(&buf, &val);
  1450→                msgpack_pack_str(mp_pck, flb_sds_len(buf));
  1451→                msgpack_pack_str_body(mp_pck, buf, flb_sds_len(buf));
  1452→                flb_sds_destroy(buf);
  1453→            }
  1454→
  1455→            msgpack_unpacked_destroy(&mp_buffer);
  1456→            if (tmp_sbuf_data) {
  1457→                flb_free(tmp_sbuf_data);
  1458→            }
  1459→
  1460→            return 0;
  1461→        }
  1462→    }
  1463→
  1464→    if (ctx->out_line_format == FLB_LOKI_FMT_JSON) {
  1465→        line = flb_msgpack_to_json_str(size_hint, rec);
  1466→        if (!line) {
  1467→            if (tmp_sbuf_data) {
  1468→                flb_free(tmp_sbuf_data);
  1469→            }
  1470→            msgpack_unpacked_destroy(&mp_buffer);
  1471→            return -1;
  1472→        }
  1473→        len = strlen(line);
  1474→        msgpack_pack_str(mp_pck, len);
  1475→        msgpack_pack_str_body(mp_pck, line, len);
  1476→        flb_free(line);
  1477→    }
  1478→    else if (ctx->out_line_format == FLB_LOKI_FMT_KV) {
  1479→        if (rec->type != MSGPACK_OBJECT_MAP) {
  1480→            msgpack_unpacked_destroy(&mp_buffer);
  1481→            if (tmp_sbuf_data) {
  1482→                flb_free(tmp_sbuf_data);
  1483→            }
  1484→            return -1;
  1485→        }
  1486→
  1487→        buf = flb_sds_create_size(size_hint);
  1488→        if (!buf) {
  1489→            msgpack_unpacked_destroy(&mp_buffer);
  1490→            if (tmp_sbuf_data) {
  1491→                flb_free(tmp_sbuf_data);
  1492→            }
  1493→            return -1;
  1494→        }
  1495→
  1496→        for (i = 0; i < rec->via.map.size; i++) {
  1497→            key = rec->via.map.ptr[i].key;
  1498→            val = rec->via.map.ptr[i].val;
  1499→
  1500→            if (key.type != MSGPACK_OBJECT_STR) {
  1501→                skip++;
  1502→                continue;
  1503→            }
  1504→
  1505→            if (i > skip) {
  1506→                safe_sds_cat(&buf, " ", 1);
  1507→            }
  1508→
  1509→            safe_sds_cat(&buf, key.via.str.ptr, key.via.str.size);
  1510→            safe_sds_cat(&buf, "=", 1);
  1511→            pack_format_line_value(&buf, &val);
  1512→        }
  1513→
  1514→        msgpack_pack_str(mp_pck, flb_sds_len(buf));
  1515→        msgpack_pack_str_body(mp_pck, buf, flb_sds_len(buf));
  1516→        flb_sds_destroy(buf);
  1517→    }
  1518→
  1519→    msgpack_unpacked_destroy(&mp_buffer);
  1520→    if (tmp_sbuf_data) {
  1521→        flb_free(tmp_sbuf_data);
  1522→    }
  1523→
  1524→    return 0;
  1525→}
  1526→
  1527→/* Initialization callback */
  1528→static int cb_loki_init(struct flb_output_instance *ins,
  1529→                        struct flb_config *config, void *data)
  1530→{
  1531→    int              result;
  1532→    struct flb_loki *ctx;
  1533→
  1534→    /* Create plugin context */
  1535→    ctx = loki_config_create(ins, config);
  1536→    if (!ctx) {
  1537→        flb_plg_error(ins, "cannot initialize configuration");
  1538→        return -1;
  1539→    }
  1540→
  1541→    result = pthread_mutex_init(&ctx->dynamic_tenant_list_lock, NULL);
  1542→
  1543→    if (result != 0) {
  1544→        flb_errno();
  1545→
  1546→        flb_plg_error(ins, "cannot initialize dynamic tenant id list lock");
  1547→
  1548→        loki_config_destroy(ctx);
  1549→
  1550→        return -1;
  1551→    }
  1552→
  1553→    result = pthread_once(&initialization_guard,
  1554→                          initialize_thread_local_storage);
  1555→
  1556→    if (result != 0) {
  1557→        flb_errno();
  1558→
  1559→        flb_plg_error(ins, "cannot initialize thread local storage");
  1560→
  1561→        loki_config_destroy(ctx);
  1562→
  1563→        return -1;
  1564→    }
  1565→
  1566→    cfl_list_init(&ctx->dynamic_tenant_list);
  1567→
  1568→    /*
  1569→     * This plugin instance uses the HTTP client interface, let's register
  1570→     * it debugging callbacks.
  1571→     */
  1572→    flb_output_set_http_debug_callbacks(ins);
  1573→
  1574→    flb_plg_info(ins,
  1575→                 "configured, hostname=%s:%i",
  1576→                 ctx->tcp_host, ctx->tcp_port);
  1577→    return 0;
  1578→}
  1579→
  1580→static flb_sds_t loki_compose_payload(struct flb_loki *ctx,
  1581→                                      int total_records,
  1582→                                      char *tag, int tag_len,
  1583→                                      const void *data, size_t bytes,
  1584→                                      flb_sds_t *dynamic_tenant_id)
  1585→{
  1586→    // int mp_ok = MSGPACK_UNPACK_SUCCESS;
  1587→    // size_t off = 0;
  1588→    flb_sds_t json;
  1589→    // struct flb_time tms;
  1590→    // msgpack_unpacked result;
  1591→    msgpack_packer mp_pck;
  1592→    msgpack_sbuffer mp_sbuf;
  1593→    // msgpack_object *obj;
  1594→    struct flb_log_event_decoder log_decoder;
  1595→    struct flb_log_event log_event;
  1596→    int ret;
  1597→
  1598→    /*
  1599→     * Fluent Bit uses Loki API v1 to push records in JSON format, this
  1600→     * is the expected structure:
  1601→     *
  1602→     * {
  1603→     *   "streams": [
  1604→     *     {
  1605→     *       "stream": {
  1606→     *         "label": "value"
  1607→     *       },
  1608→     *       "values": [
  1609→     *         [ "<unix epoch in nanoseconds>", "<log line>" ],
  1610→     *         [ "<unix epoch in nanoseconds>", "<log line>" ]
  1611→     *       ]
  1612→     *     }
  1613→     *   ]
  1614→     * }
  1615→     *
  1616→     * As of Loki 3.0, log entries may optionally contain a third element which is a JSON
  1617→     * object indicating structured metadata:
  1618→     *
  1619→     * "values": [
  1620→     *     [ "<unix epoch in nanoseconds>", "<log line>", {"trace_id": "0242ac120002"}]
  1621→     * ]
  1622→     */
  1623→
  1624→    ret = flb_log_event_decoder_init(&log_decoder, (char *) data, bytes);
  1625→
  1626→    if (ret != FLB_EVENT_DECODER_SUCCESS) {
  1627→        flb_plg_error(ctx->ins,
  1628→                      "Log event decoder initialization error : %d", ret);
  1629→
  1630→        return NULL;
  1631→    }
  1632→
  1633→    /* Initialize msgpack buffers */
  1634→    msgpack_sbuffer_init(&mp_sbuf);
  1635→    msgpack_packer_init(&mp_pck, &mp_sbuf, msgpack_sbuffer_write);
  1636→
  1637→    /* Main map */
  1638→    msgpack_pack_map(&mp_pck, 1);
  1639→
  1640→    /* streams */
  1641→    msgpack_pack_str(&mp_pck, 7);
  1642→    msgpack_pack_str_body(&mp_pck, "streams", 7);
  1643→
  1644→    if (ctx->ra_used == 0 && ctx->auto_kubernetes_labels == FLB_FALSE) {
  1645→        /*
  1646→         * If labels are cached, there is no record accessor or custom
  1647→         * keys, so it's safe to put one main stream and attach all the
  1648→         * values.
  1649→         */
  1650→        msgpack_pack_array(&mp_pck, 1);
  1651→
  1652→        /* map content: streams['stream'] & streams['values'] */
  1653→        msgpack_pack_map(&mp_pck, 2);
  1654→
  1655→        /* streams['stream'] */
  1656→        msgpack_pack_str(&mp_pck, 6);
  1657→        msgpack_pack_str_body(&mp_pck, "stream", 6);
  1658→
  1659→        /* Pack stream labels */
  1660→        pack_labels(ctx, &mp_pck, tag, tag_len, NULL);
  1661→
  1662→        /* streams['values'] */
  1663→        msgpack_pack_str(&mp_pck, 6);
  1664→        msgpack_pack_str_body(&mp_pck, "values", 6);
  1665→        msgpack_pack_array(&mp_pck, total_records);
  1666→
  1667→        while ((ret = flb_log_event_decoder_next(
  1668→                        &log_decoder,
  1669→                        &log_event)) == FLB_EVENT_DECODER_SUCCESS) {
  1670→            msgpack_pack_array(&mp_pck, ctx->structured_metadata ||
  1671→                               ctx->structured_metadata_map_keys ? 3 : 2);
  1672→
  1673→            /* Append the timestamp */
  1674→            pack_timestamp(&mp_pck, &log_event.timestamp);
  1675→            pack_record(ctx, &mp_pck, log_event.body, dynamic_tenant_id);
  1676→            if (ctx->structured_metadata || ctx->structured_metadata_map_keys) {
  1677→                pack_structured_metadata(ctx, &mp_pck, tag, tag_len, NULL);
  1678→            }
  1679→        }
  1680→    }
  1681→    else {
  1682→        /*
  1683→         * Here there are no cached labels and the labels are composed by
  1684→         * each record content. To simplify the operation just create
  1685→         * one stream per record.
  1686→         */
  1687→        msgpack_pack_array(&mp_pck, total_records);
  1688→
  1689→        while ((ret = flb_log_event_decoder_next(
  1690→                        &log_decoder,
  1691→                        &log_event)) == FLB_EVENT_DECODER_SUCCESS) {
  1692→            /* map content: streams['stream'] & streams['values'] */
  1693→            msgpack_pack_map(&mp_pck, 2);
  1694→
  1695→            /* streams['stream'] */
  1696→            msgpack_pack_str(&mp_pck, 6);
  1697→            msgpack_pack_str_body(&mp_pck, "stream", 6);
  1698→
  1699→            /* Pack stream labels */
  1700→            pack_labels(ctx, &mp_pck, tag, tag_len, log_event.body);
  1701→
  1702→            /* streams['values'] */
  1703→            msgpack_pack_str(&mp_pck, 6);
  1704→            msgpack_pack_str_body(&mp_pck, "values", 6);
  1705→            msgpack_pack_array(&mp_pck, 1);
  1706→
  1707→            msgpack_pack_array(&mp_pck, ctx->structured_metadata ||
  1708→                               ctx->structured_metadata_map_keys ? 3 : 2);
  1709→
  1710→            /* Append the timestamp */
  1711→            pack_timestamp(&mp_pck, &log_event.timestamp);
  1712→            pack_record(ctx, &mp_pck, log_event.body, dynamic_tenant_id);
  1713→            if (ctx->structured_metadata || ctx->structured_metadata_map_keys) {
  1714→                pack_structured_metadata(ctx, &mp_pck, tag, tag_len, log_event.body);
  1715→            }
  1716→        }
  1717→    }
  1718→
  1719→    flb_log_event_decoder_destroy(&log_decoder);
  1720→
  1721→    json = flb_msgpack_raw_to_json_sds(mp_sbuf.data, mp_sbuf.size);
  1722→
  1723→    msgpack_sbuffer_destroy(&mp_sbuf);
  1724→
  1725→    return json;
  1726→}
  1727→
  1728→static void payload_release(void *payload, int compressed)
  1729→{
  1730→    if (compressed) {
  1731→        flb_free(payload);
  1732→    }
  1733→    else {
  1734→        flb_sds_destroy(payload);
  1735→    }
  1736→}
  1737→
  1738→static void cb_loki_flush(struct flb_event_chunk *event_chunk,
  1739→                          struct flb_output_flush *out_flush,
  1740→                          struct flb_input_instance *i_ins,
  1741→                          void *out_context,
  1742→                          struct flb_config *config)
  1743→{
  1744→    int ret;
  1745→    int out_ret = FLB_OK;
  1746→    size_t b_sent;
  1747→    flb_sds_t payload = NULL;
  1748→    flb_sds_t out_buf = NULL;
  1749→    size_t out_size;
  1750→    int compressed = FLB_FALSE;
  1751→    struct flb_loki *ctx = out_context;
  1752→    struct flb_connection *u_conn;
  1753→    struct flb_http_client *c;
  1754→    struct flb_loki_dynamic_tenant_id_entry *dynamic_tenant_id;
  1755→    struct mk_list *head;
  1756→    struct flb_config_map_val *mv;
  1757→    struct flb_slist_entry *key = NULL;
  1758→    struct flb_slist_entry *val = NULL;
  1759→
  1760→    dynamic_tenant_id = FLB_TLS_GET(thread_local_tenant_id);
  1761→
  1762→    if (dynamic_tenant_id == NULL) {
  1763→        dynamic_tenant_id = dynamic_tenant_id_create();
  1764→
  1765→        if (dynamic_tenant_id == NULL) {
  1766→            flb_errno();
  1767→            flb_plg_error(ctx->ins, "cannot allocate dynamic tenant id");
  1768→
  1769→            FLB_OUTPUT_RETURN(FLB_RETRY);
  1770→        }
  1771→
  1772→        FLB_TLS_SET(thread_local_tenant_id, dynamic_tenant_id);
  1773→
  1774→        pthread_mutex_lock(&ctx->dynamic_tenant_list_lock);
  1775→
  1776→        cfl_list_add(&dynamic_tenant_id->_head, &ctx->dynamic_tenant_list);
  1777→
  1778→        pthread_mutex_unlock(&ctx->dynamic_tenant_list_lock);
  1779→    }
  1780→
  1781→    /* Format the data to the expected Newrelic Payload */
  1782→    payload = loki_compose_payload(ctx,
  1783→                                   event_chunk->total_events,
  1784→                                   (char *) event_chunk->tag,
  1785→                                   flb_sds_len(event_chunk->tag),
  1786→                                   event_chunk->data, event_chunk->size,
  1787→                                   &dynamic_tenant_id->value);
  1788→
  1789→    if (!payload) {
  1790→        flb_plg_error(ctx->ins, "cannot compose request payload");
  1791→
  1792→        FLB_OUTPUT_RETURN(FLB_RETRY);
  1793→    }
  1794→
  1795→    /* Map buffer */
  1796→    out_buf = payload;
  1797→    out_size = flb_sds_len(payload);
  1798→
  1799→    if (ctx->compress_gzip == FLB_TRUE) {
  1800→        ret = flb_gzip_compress((void *) payload, flb_sds_len(payload), (void **) &out_buf, &out_size);
  1801→        if (ret == -1) {
  1802→            flb_plg_error(ctx->ins,
  1803→                          "cannot gzip payload, disabling compression");
  1804→        } else {
  1805→            compressed = FLB_TRUE;
  1806→            /* payload is not longer needed */
  1807→            flb_sds_destroy(payload);
  1808→        }
  1809→    }
  1810→
  1811→    /* Lookup an available connection context */
  1812→    u_conn = flb_upstream_conn_get(ctx->u);
  1813→    if (!u_conn) {
  1814→        flb_plg_error(ctx->ins, "no upstream connections available");
  1815→
  1816→        payload_release(out_buf, compressed);
  1817→
  1818→        FLB_OUTPUT_RETURN(FLB_RETRY);
  1819→    }
  1820→
  1821→    /* Create HTTP client context */
  1822→    c = flb_http_client(u_conn, FLB_HTTP_POST, ctx->uri,
  1823→                        out_buf, out_size,
  1824→                        ctx->tcp_host, ctx->tcp_port,
  1825→                        NULL, 0);
  1826→    if (!c) {
  1827→        flb_plg_error(ctx->ins, "cannot create HTTP client context");
  1828→
  1829→        payload_release(out_buf, compressed);
  1830→        flb_upstream_conn_release(u_conn);
  1831→
  1832→        FLB_OUTPUT_RETURN(FLB_RETRY);
  1833→    }
  1834→
  1835→    /* Set response buffer size */
  1836→    flb_http_buffer_size(c, ctx->http_buffer_max_size);
  1837→
  1838→    /* Set callback context to the HTTP client context */
  1839→    flb_http_set_callback_context(c, ctx->ins->callback);
  1840→
  1841→    /* User Agent */
  1842→    flb_http_add_header(c, "User-Agent", 10, "Fluent-Bit", 10);
  1843→
  1844→    /* Auth headers */
  1845→    if (ctx->http_user && ctx->http_passwd) { /* Basic */
  1846→        flb_http_basic_auth(c, ctx->http_user, ctx->http_passwd);
  1847→    } else if (ctx->bearer_token) { /* Bearer token */
  1848→        flb_http_bearer_auth(c, ctx->bearer_token);
  1849→    }
  1850→
  1851→    /* Arbitrary additional headers */
  1852→    flb_config_map_foreach(head, mv, ctx->headers) {
  1853→        key = mk_list_entry_first(mv->val.list, struct flb_slist_entry, _head);
  1854→        val = mk_list_entry_last(mv->val.list, struct flb_slist_entry, _head);
  1855→
  1856→        flb_http_add_header(c,
  1857→                            key->str, flb_sds_len(key->str),
  1858→                            val->str, flb_sds_len(val->str));
  1859→    }
  1860→
  1861→    /* Add Content-Type header */
  1862→    flb_http_add_header(c,
  1863→                        FLB_LOKI_CT, sizeof(FLB_LOKI_CT) - 1,
  1864→                        FLB_LOKI_CT_JSON, sizeof(FLB_LOKI_CT_JSON) - 1);
  1865→
  1866→    if (compressed == FLB_TRUE) {
  1867→        flb_http_set_content_encoding_gzip(c);
  1868→    }
  1869→
  1870→    /* Add X-Scope-OrgID header */
  1871→    if (dynamic_tenant_id->value != NULL) {
  1872→        flb_http_add_header(c,
  1873→                            FLB_LOKI_HEADER_SCOPE, sizeof(FLB_LOKI_HEADER_SCOPE) - 1,
  1874→                            dynamic_tenant_id->value,
  1875→                            flb_sds_len(dynamic_tenant_id->value));
  1876→    }
  1877→    else if (ctx->tenant_id) {
  1878→        flb_http_add_header(c,
  1879→                            FLB_LOKI_HEADER_SCOPE, sizeof(FLB_LOKI_HEADER_SCOPE) - 1,
  1880→                            ctx->tenant_id, flb_sds_len(ctx->tenant_id));
  1881→    }
  1882→
  1883→    /* Send HTTP request */
  1884→    ret = flb_http_do(c, &b_sent);
  1885→    payload_release(out_buf, compressed);
  1886→
  1887→    /* Validate HTTP client return status */
  1888→    if (ret == 0) {
  1889→        /*
  1890→         * Only allow the following HTTP status:
  1891→         *
  1892→         * - 200: OK
  1893→         * - 201: Created
  1894→         * - 202: Accepted
  1895→         * - 203: no authorative resp
  1896→         * - 204: No Content
  1897→         * - 205: Reset content
  1898→         *
  1899→         */
  1900→        if (c->resp.status == 400) {
  1901→            /*
  1902→             * Loki will return 400 if incoming data is out of order.
  1903→             * We should not retry such data.
  1904→             */
  1905→            flb_plg_error(ctx->ins, "%s:%i, HTTP status=%i Not retrying.\n%s",
  1906→                          ctx->tcp_host, ctx->tcp_port, c->resp.status,
  1907→                          c->resp.payload);
  1908→            out_ret = FLB_ERROR;
  1909→        }
  1910→        else if (c->resp.status >= 500 && c->resp.status <= 599) {
  1911→            if (c->resp.payload) {
  1912→                flb_plg_error(ctx->ins, "could not flush records to %s:%i"
  1913→                            " HTTP status=%i",
  1914→                            ctx->tcp_host, ctx->tcp_port, c->resp.status);
  1915→                flb_plg_trace(ctx->ins, "Response was:\n%s",
  1916→                            c->resp.payload);
  1917→            }
  1918→            else {
  1919→                flb_plg_error(ctx->ins, "could not flush records to %s:%i"
  1920→                            " HTTP status=%i",
  1921→                            ctx->tcp_host, ctx->tcp_port, c->resp.status);
  1922→            }
  1923→            /*
  1924→             * Server-side error occured, do not reuse this connection for retry.
  1925→             * This could be an issue of Loki gateway.
  1926→             * Rather initiate new connection.
  1927→             */
  1928→            flb_plg_trace(ctx->ins, "Destroying connection for %s:%i",
  1929→                          ctx->tcp_host, ctx->tcp_port);
  1930→            flb_upstream_conn_recycle(u_conn, FLB_FALSE);
  1931→            out_ret = FLB_RETRY;
  1932→        }
  1933→        else if (c->resp.status < 200 || c->resp.status > 205) {
  1934→            if (c->resp.payload) {
  1935→                flb_plg_error(ctx->ins, "%s:%i, HTTP status=%i\n%s",
  1936→                              ctx->tcp_host, ctx->tcp_port, c->resp.status,
  1937→                              c->resp.payload);
  1938→            }
  1939→            else {
  1940→                flb_plg_error(ctx->ins, "%s:%i, HTTP status=%i",
  1941→                              ctx->tcp_host, ctx->tcp_port, c->resp.status);
  1942→            }
  1943→            out_ret = FLB_RETRY;
  1944→        }
  1945→        else {
  1946→            if (c->resp.payload) {
  1947→                flb_plg_debug(ctx->ins, "%s:%i, HTTP status=%i\n%s",
  1948→                              ctx->tcp_host, ctx->tcp_port,
  1949→                              c->resp.status, c->resp.payload);
  1950→            }
  1951→            else {
  1952→                flb_plg_debug(ctx->ins, "%s:%i, HTTP status=%i",
  1953→                              ctx->tcp_host, ctx->tcp_port,
  1954→                              c->resp.status);
  1955→            }
  1956→        }
  1957→    }
  1958→    else {
  1959→        flb_plg_error(ctx->ins, "could not flush records to %s:%i (http_do=%i)",
  1960→                      ctx->tcp_host, ctx->tcp_port, ret);
  1961→        out_ret = FLB_RETRY;
  1962→    }
  1963→
  1964→    flb_http_client_destroy(c);
  1965→    flb_upstream_conn_release(u_conn);
  1966→
  1967→    FLB_OUTPUT_RETURN(out_ret);
  1968→}
  1969→
  1970→static void release_dynamic_tenant_ids(struct cfl_list *dynamic_tenant_list)
  1971→{
  1972→    struct cfl_list                         *iterator;
  1973→    struct cfl_list                         *backup;
  1974→    struct flb_loki_dynamic_tenant_id_entry *entry;
  1975→
  1976→    cfl_list_foreach_safe(iterator, backup, dynamic_tenant_list) {
  1977→        entry = cfl_list_entry(iterator,
  1978→                               struct flb_loki_dynamic_tenant_id_entry,
  1979→                               _head);
  1980→
  1981→        dynamic_tenant_id_destroy(entry);
  1982→    }
  1983→}
  1984→
  1985→static int cb_loki_exit(void *data, struct flb_config *config)
  1986→{
  1987→    struct flb_loki *ctx = data;
  1988→
  1989→    if (!ctx) {
  1990→        return 0;
  1991→    }
  1992→
  1993→    pthread_mutex_lock(&ctx->dynamic_tenant_list_lock);
  1994→
  1995→    release_dynamic_tenant_ids(&ctx->dynamic_tenant_list);
  1996→
  1997→    pthread_mutex_unlock(&ctx->dynamic_tenant_list_lock);
  1998→
  1999→    loki_config_destroy(ctx);
  2000→
  2001→    return 0;
  2002→}
