#include <fluent-bit/flb_output_plugin.h>
#include <fluent-bit/flb_config.h>
#include <fluent-bit/multiprocess/flb_mp.h>
#include <fluent-bit/flb_record_accessor.h>
#include <fluent-bit/flb_slist.h>
#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <string.h>

#define NUM_THREADS 4
#define NUM_ITERATIONS 100

struct test_record {
    char *kubernetes_pod_name;
    char *severity;
    char *k8s_cluster_name;
    char *log;
};

static struct test_record test_records[] = {
    {"pod-name-01", "warn", "cls01", "message"},
    {"pod-name-02", "error", "cls01", "another message"},
    {"pod-name-03", "info", "cls02", "info message"}
};

static int num_test_records = sizeof(test_records) / sizeof(test_records[0]);

void *process_records(void *arg) {
    struct mk_list *patterns = (struct mk_list *)arg;
    int errors = 0;

    for (int i = 0; i < NUM_ITERATIONS; i++) {
        struct test_record *rec = &test_records[i % num_test_records];

        // Create msgpack map representing the record
        msgpack_sbuffer buf;
        msgpack_sbuffer_init(&buf);
        msgpack_packer pk;
        msgpack_packer_init(&pk, &buf, msgpack_sbuffer_write);

        msgpack_pack_map(&pk, 4);

        msgpack_pack_str(&pk, 3);
        msgpack_pack_str_body(&pk, "log", 3);
        msgpack_pack_str(&pk, strlen(rec->log));
        msgpack_pack_str_body(&pk, rec->log, strlen(rec->log));

        msgpack_pack_str(&pk, 10);
        msgpack_pack_str_body(&pk, "kubernetes", 10);
        msgpack_pack_map(&pk, 1);
        msgpack_pack_str(&pk, 8);
        msgpack_pack_str_body(&pk, "pod_name", 8);
        msgpack_pack_str(&pk, strlen(rec->kubernetes_pod_name));
        msgpack_pack_str_body(&pk, rec->kubernetes_pod_name, strlen(rec->kubernetes_pod_name));

        msgpack_pack_str(&pk, 8);
        msgpack_pack_str_body(&pk, "severity", 8);
        msgpack_pack_str(&pk, strlen(rec->severity));
        msgpack_pack_str_body(&pk, rec->severity, strlen(rec->severity));

        msgpack_pack_str(&pk, 16);
        msgpack_pack_str_body(&pk, "k8s_cluster_name", 16);
        msgpack_pack_str(&pk, strlen(rec->k8s_cluster_name));
        msgpack_pack_str_body(&pk, rec->k8s_cluster_name, strlen(rec->k8s_cluster_name));

        // Unpack the buffer
        msgpack_unpacked result;
        msgpack_unpacked_init(&result);
        size_t off = 0;

        if (msgpack_unpack_next(&result, buf.data, buf.size, &off) != MSGPACK_UNPACK_SUCCESS) {
            fprintf(stderr, "Failed to unpack record\n");
            msgpack_sbuffer_destroy(&buf);
            errors++;
            continue;
        }

        // Create multi-pattern accessor
        struct flb_mp_accessor *mpa = flb_mp_accessor_create(patterns);
        if (!mpa) {
            fprintf(stderr, "Failed to create multi-pattern accessor\n");
            msgpack_unpacked_destroy(&result);
            msgpack_sbuffer_destroy(&buf);
            errors++;
            continue;
        }

        // Remove keys
        void *out_buf = NULL;
        size_t out_size = 0;
        int ret = flb_mp_accessor_keys_remove(mpa, &result.data, &out_buf, &out_size);

        if (ret == FLB_TRUE) {
            // Check if all keys were removed
            msgpack_unpacked final_result;
            msgpack_unpacked_init(&final_result);
            off = 0;

            if (msgpack_unpack_next(&final_result, out_buf, out_size, &off) == MSGPACK_UNPACK_SUCCESS) {
                if (final_result.data.type == MSGPACK_OBJECT_MAP) {
                    int remaining_keys = final_result.data.via.map.size;

                    // Check each key that should remain
                    int log_found = 0;

                    for (int j = 0; j < remaining_keys; j++) {
                        msgpack_object key = final_result.data.via.map.ptr[j].key;
                        if (key.type == MSGPACK_OBJECT_STR) {
                            if (strncmp(key.via.str.ptr, "log", key.via.str.size) == 0) {
                                log_found = 1;
                            } else {
                                // Found a key that should have been removed
                                fprintf(stderr, "Thread %lu: Found key that should be removed: %.*s\n",
                                        pthread_self(), (int)key.via.str.size, key.via.str.ptr);
                                errors++;
                            }
                        }
                    }

                    if (!log_found) {
                        fprintf(stderr, "Thread %lu: Expected key 'log' not found\n", pthread_self());
                        errors++;
                    }
                }
            }

            msgpack_unpacked_destroy(&final_result);
            flb_free(out_buf);
        }

        flb_mp_accessor_destroy(mpa);
        msgpack_unpacked_destroy(&result);
        msgpack_sbuffer_destroy(&buf);
    }

    return (void *)(long)errors;
}

int main() {
    // Create remove keys patterns
    struct mk_list remove_patterns;
    flb_slist_create(&remove_patterns);

    // Add keys to remove (same as in the bug report)
    flb_slist_add(&remove_patterns, "$kubernetes");
    flb_slist_add(&remove_patterns, "$severity");
    flb_slist_add(&remove_patterns, "$k8s_cluster_name");

    printf("Testing Loki Remove_Keys functionality with %d threads and %d iterations per thread\n",
           NUM_THREADS, NUM_ITERATIONS);

    pthread_t threads[NUM_THREADS];
    int total_errors = 0;

    // Create threads
    for (int i = 0; i < NUM_THREADS; i++) {
        if (pthread_create(&threads[i], NULL, process_records, &remove_patterns) != 0) {
            fprintf(stderr, "Failed to create thread %d\n", i);
            continue;
        }
    }

    // Wait for threads to complete
    for (int i = 0; i < NUM_THREADS; i++) {
        void *thread_errors;
        pthread_join(threads[i], &thread_errors);
        total_errors += (int)(long)thread_errors;
    }

    // Cleanup
    flb_slist_destroy(&remove_patterns);

    if (total_errors > 0) {
        printf("TEST FAILED: Found %d errors in %d iterations\n",
               total_errors, NUM_THREADS * NUM_ITERATIONS);
        return 1;
    } else {
        printf("TEST PASSED: All %d iterations completed successfully\n",
               NUM_THREADS * NUM_ITERATIONS);
        return 0;
    }
}

