#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <pthread.h>
#include <assert.h>

// Simulate the problematic part of Remove_Keys functionality
// This reproduces the race condition in the pattern matching logic

typedef struct {
    int matched;
    char *pattern;
    char cached_key[64];
} pattern_match_t;

typedef struct {
    pattern_match_t *matches;
    int matches_size;
    int cached_key_valid;  // Issue: This can be corrupted by multiple threads
} mp_accessor_t;

// Simulate the race condition scenario
mp_accessor_t g_mpa = {0};

void prepare_patterns() {
    static const char *PATTERNS[] = {
        "$kubernetes",
        "$severity",
        "$k8s_cluster_name"
    };
    int num_patterns = sizeof(PATTERNS) / sizeof(PATTERNS[0]);

    g_mpa.matches_size = num_patterns;
    g_mpa.matches = malloc(sizeof(pattern_match_t) * num_patterns);
    g_mpa.cached_key_valid = 0;

    for (int i = 0; i < num_patterns; i++) {
        g_mpa.matches[i].pattern = (char *)PATTERNS[i];
        g_mpa.matches[i].matched = 0;
        memset(g_mpa.matches[i].cached_key, 0, sizeof(g_mpa.matches[i].cached_key));
    }
}

void cleanup_patterns() {
    if (g_mpa.matches) {
        free(g_mpa.matches);
        g_mpa.matches = NULL;
        g_mpa.matches_size = 0;
    }
}

// Simulate the race condition in accessor_key_find_matches
int find_matches_race(char *key) {
    // Problem: Multiple threads may access/modify cached_key_valid simultaneously
    if (g_mpa.cached_key_valid) {
        // Thread 2 might set this to 0 while Thread 1 is checking it
        return 1;
    }

    // This is where the race occurs - setting cached_key_valid
    // Thread 1 sets it to 1, but Thread 2 might set it to 0 simultaneously
    g_mpa.cached_key_valid = 1;

    // Simulate finding matches
    int matches = 0;
    for (int i = 0; i < g_mpa.matches_size; i++) {
        // Thread might read corrupted pattern due to race
        if (strstr(key, g_mpa.matches[i].pattern) != NULL) {
            matches++;
        }
    }

    // Another race window: setting cached_key_valid back
    g_mpa.cached_key_valid = 0;

    return matches;
}

// Simulate the race condition in accessor_sub_pack
int process_subpack(char *key, char *value) {
    // Race condition: multiple threads accessing matches array
    int should_pack = 1;

    for (int i = 0; i < g_mpa.matches_size; i++) {
        // Thread might read corrupted match state
        if (g_mpa.matches[i].matched) {
            // Race: multiple threads might corrupt cached_key simultaneously
            strncpy(g_mpa.matches[i].cached_key, key, 63);

            // This is where keys get partially removed due to race
            if (strcmp(key, "kubernetes") == 0 || strcmp(key, "severity") == 0) {
                should_pack = 0; // Remove this key
            }
        }
    }

    return should_pack;
}

// Thread function that reproduces the race condition
void *process_record(void *arg) {
    int iterations = *(int *)arg;
    int errors = 0;

    char *keys[] = {"log", "kubernetes", "severity", "k8s_cluster_name"};
    int num_keys = sizeof(keys) / sizeof(keys[0]);

    for (int i = 0; i < iterations; i++) {
        int remaining_keys = 0;

        for (int j = 0; j < num_keys; j++) {
            // Simulate the race condition
            int matches = find_matches_race(keys[j]);

            // Race condition in subpack processing
            int should_pack = process_subpack(keys[j], "value");

            if (should_pack) {
                remaining_keys++;
            }
        }

        // Check for inconsistent behavior (the bug)
        if (remaining_keys != 1) { // Should only have "log" remaining
            printf("Thread %lu: Inconsistent key removal - remaining keys: %d\n",
                   pthread_self(), remaining_keys);
            errors++;
        }
