#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <pthread.h>
#include <assert.h>

// Fixed version that avoids the race condition by using local storage
typedef struct {
    int matched;
    char *pattern;
    char cached_key[64];
} pattern_match_t;

typedef struct {
    pattern_match_t *matches;
    int matches_size;
    pthread_mutex_t lock;  // Add mutex for thread safety
} mp_accessor_t;

mp_accessor_t g_mpa = {0};

void prepare_patterns() {
    static const char *PATTERNS[] = {
        "$kubernetes",
        "$severity",
        "$k8s_cluster_name"
    };
    int num_patterns = sizeof(PATTERNS) / sizeof(PATTERNS[0]);

    g_mpa.matches_size = num_patterns;
    g_mpa.matches = malloc(sizeof(pattern_match_t) * num_patterns);
    pthread_mutex_init(&g_mpa.lock, NULL);

    for (int i = 0; i < num_patterns; i++) {
        g_mpa.matches[i].pattern = (char *)PATTERNS[i];
        g_mpa.matches[i].matched = 0;
        memset(g_mpa.matches[i].cached_key, 0, sizeof(g_mpa.matches[i].cached_key));
    }
}

void cleanup_patterns() {
    if (g_mpa.matches) {
        free(g_mpa.matches);
        g_mpa.matches = NULL;
        g_mpa.matches_size = 0;
    }
    pthread_mutex_destroy(&g_mpa.lock);
}

// Fixed: Create local matches array to avoid shared state
int find_matches_fixed(char *key, pattern_match_t *local_matches) {
    int matches = 0;

    // Copy matches locally to avoid races
    for (int i = 0; i < g_mpa.matches_size; i++) {
        local_matches[i] = g_mpa.matches[i];
    }

    for (int i = 0; i < g_mpa.matches_size; i++) {
        if (strstr(key, local_matches[i].pattern) != NULL) {
            matches++;
        }
    }

    return matches;
}

// Fixed: Use local matches
int process_subpack_fixed(char *key, char *value, pattern_match_t *local_matches) {
    int should_pack = 1;

    for (int i = 0; i < g_mpa.matches_size; i++) {
        // Safe to read from local copy
        if (local_matches[i].matched) {
            // Safe to write to local copy
            strncpy(local_matches[i].cached_key, key, 63);

            if (strcmp(key, "kubernetes") == 0 || strcmp(key, "severity") == 0 ||
                strcmp(key, "k8s_cluster_name") == 0) {
                should_pack = 0; // Remove this key
            }
        }
    }

    return should_pack;
}

// Thread function with fixed race condition
void *process_record_fixed(void *arg) {
    int iterations = *(int *)arg;
    int errors = 0;

    char *keys[] = {"log", "kubernetes", "severity", "k8s_cluster_name"};
    int num_keys = sizeof(keys) / sizeof(keys[0]);

    // Create local storage for this thread
    pattern_match_t *local_matches = malloc(sizeof(pattern_match_t) * g_mpa.matches_size);
    if (!local_matches) {
        return (void *)(long)-1;
    }

    for (int i = 0; i < iterations; i++) {
        int remaining_keys = 0;

        for (int j = 0; j < num_keys; j++) {
            // Use local matches to avoid race conditions
            int matches = find_matches_fixed(keys[j], local_matches);

            // Use local matches for subpack processing
            int should_pack = process_subpack_fixed(keys[j], "value", local_matches);

            if (should_pack) {
                remaining_keys++;
            }
        }

        // Check for consistent behavior - should only have "log" remaining
        if (remaining_keys != 1 || strcmp(keys[0], "log") != 0) {
            errors++;
        }
    }

    free(local_matches);
    printf("Thread %lu: Completed with %d errors\n", pthread_self(), errors);
    return (void *)(long)errors;
}

int main() {
    printf("Testing fixed Loki Remove_Keys functionality\n");
    printf("Expected behavior: Only 'log' key should remain after removing kubernetes, severity, k8s_cluster_name\n\n");

    prepare_patterns();

    const int NUM_THREADS = 4;
    const int ITERATIONS = 10000;

    pthread_t threads[NUM_THREADS];
    int thread_args = ITERATIONS;

    // Create threads
    for (int i = 0; i < NUM_THREADS; i++) {
        if (pthread_create(&threads[i], NULL, process_record_fixed, &thread_args) != 0) {
            perror("Failed to create thread");
            return 1;
        }
    }

    // Wait for threads
    int total_errors = 0;
    for (int i = 0; i < NUM_THREADS; i++) {
        void *result;
        pthread_join(threads[i], &result);
        total_errors += (int)(long)result;
    }

    cleanup_patterns();

    printf("\nTest completed:\n");
    printf("Total iterations: %d\n", NUM_THREADS * ITERATIONS);
    printf("Errors detected: %d\n", total_errors);

    if (total_errors == 0) {
        printf("SUCCESS: No race conditions detected - fix is working correctly\n");
        return 0;
    } else {
        printf("FAILED: Still have %d errors\n", total_errors);
        return 1;
    }
}

