    for (int i = 0; i < iterations; i++) {
        int remaining_keys = 0;

        for (int j = 0; j < num_keys; j++) {
            // Use local matches to avoid race conditions
            int matches = find_matches_fixed(keys[j], local_matches);

            // Use local matches for subpack processing
            int should_pack = process_subpack_fixed(keys[j], "value", local_matches);

            if (should_pack) {
                remaining_keys++;
            }
        }

        // Check for consistent behavior - should only have "log" remaining
        if (remaining_keys != 1 || strcmp(keys[0], "log") != 0) {
            errors++;
        }
    }

    free(local_matches);
    printf("Thread %lu: Completed with %d errors\n", pthread_self(), errors);
    return (void *)(long)errors;
}

int main() {
    printf("Testing fixed Loki Remove_Keys functionality\n");
    printf("Expected behavior: Only 'log' key should remain after removing kubernetes, severity, k8s_cluster_name\n\n");

    prepare_patterns();

    const int NUM_THREADS = 4;
    const int ITERATIONS = 10000;

    pthread_t threads[NUM_THREADS];
    int thread_args = ITERATIONS;

    // Create threads
    for (int i = 0; i < NUM_THREADS; i++) {
        if (pthread_create(&threads[i], NULL, process_record_fixed, &thread_args) != 0) {
            perror("Failed to create thread");
            return 1;
        }
    }

    // Wait for threads
    int total_errors = 0;
    for (int i = 0; i < NUM_THREADS; i++) {
        void *result;
        pthread_join(threads[i], &result);
        total_errors += (int)(long)result;
    }

    cleanup_patterns();

    printf("\nTest completed:\n");
    printf("Total iterations: %d\n", NUM_THREADS * ITERATIONS);
    printf("Errors detected: %d\n", total_errors);

    if (total_errors == 0) {
        printf("SUCCESS: No race conditions detected - fix is working correctly\n");
        return 0;
    } else {
        printf("FAILED: Still have %d errors\n", total_errors);
        return 1;
    }
}
